span.p:
POST /api/launch
req: { project? }
200: launched + projectName + sceneObjectCount

POST /api/project/new
req: { templateId?, projectName? }
200: created + projectPath + a3pSizeBytes

POST /api/scene/add-object
req: { className, name? }
200: added + evidenceArtifact

POST /api/code/edit-procedure
req: { procedureSelector?, editSpec? }
200: proof result + artifact names

POST /api/code/create-procedure
req: { name, parameters? }
200: created procedure + totalProcedures

POST /api/code/create-function
req: { name, returnType, parameters? }
200: created function + totalProcedures

POST /api/project/save
req: { saveSelector?, targetPath? }
200: saved + artifact names

POST /api/events/fire
req: { eventType, payload? }
200: triggered[] + evidenceArtifact
